CREATE TABLE fee_types (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    name        text NOT NULL,
    description text,
    is_active   boolean NOT NULL DEFAULT true,
    is_deleted  boolean NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);

-- ---------------------------------------------------------------------------
-- 3. fee_accounts
-- ---------------------------------------------------------------------------
CREATE TABLE fee_accounts (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id      uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    term_id         uuid NOT NULL REFERENCES terms(id) ON DELETE CASCADE,
    academic_year_id uuid NOT NULL REFERENCES academic_years(id) ON DELETE CASCADE,
    total_expected  numeric NOT NULL DEFAULT 0,
    total_paid      numeric NOT NULL DEFAULT 0,
    total_fees      numeric NOT NULL DEFAULT 0,
    total_discount  numeric NOT NULL DEFAULT 0,
    balance         numeric NOT NULL DEFAULT 0,
    status          fee_account_status NOT NULL DEFAULT 'unpaid',
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false,
    UNIQUE (student_id, term_id)
);
COMMENT ON COLUMN fee_accounts.total_fees     IS 'Gross fees before discounts. Set by recalculate_fee_account().';
COMMENT ON COLUMN fee_accounts.total_discount IS 'Sum of applied discounts. total_expected = total_fees - total_discount.';

-- ---------------------------------------------------------------------------
-- 4. fee_payments
--    term_id column added (00059) so dashboard trend/method aggregates
--    can filter by term directly without a fee_accounts join.
--    mobile_money_provider / phone_used / received_by_user_id dropped
--    (dead columns, section D).
-- ---------------------------------------------------------------------------
CREATE TABLE fee_payments (
    id                      uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id               uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    fee_account_id          uuid NOT NULL REFERENCES fee_accounts(id) ON DELETE CASCADE,
    student_id              uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    term_id                 uuid REFERENCES terms(id) ON DELETE SET NULL,
    amount                  numeric NOT NULL,
    payment_method          payment_method NOT NULL,
    mobile_money_transaction_id text,
    mobile_money_provider   text CHECK (mobile_money_provider IN ('mtn', 'airtel')),
    phone_used              text,
    pesapal_order_tracking_id text,
    pesapal_tx_id           text,
    received_by_user_id     uuid REFERENCES users(id) ON DELETE SET NULL,
    payment_date            date NOT NULL DEFAULT current_date,
    notes                   text,
    receipt_number          text,
    status                  payment_status NOT NULL DEFAULT 'pending',
    created_at              timestamptz NOT NULL DEFAULT now(),
    updated_at              timestamptz NOT NULL DEFAULT now(),
    is_deleted              boolean NOT NULL DEFAULT false
);
COMMENT ON COLUMN fee_payments.mobile_money_provider IS 'Mobile money network (mtn/airtel) from detectMobileMoneyProvider(). Lowercase only.';
COMMENT ON COLUMN fee_payments.received_by_user_id   IS 'Staff who recorded/received the payment. Audit trail.';

-- ---------------------------------------------------------------------------
-- 5. fee_discounts
-- ---------------------------------------------------------------------------
-- discount_type is text + CHECK (not the discount_type enum) because the
-- app writes 'fixed' in addition to the enum's 'percentage'/'fixed_amount'.
CREATE TABLE fee_discounts (
    id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id     uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    name          text NOT NULL,
    description   text,
    discount_type text NOT NULL DEFAULT 'percentage'
                  CHECK (discount_type IN ('percentage', 'fixed_amount', 'fixed')),
    value         numeric NOT NULL DEFAULT 0,
    is_active     boolean NOT NULL DEFAULT true,
    created_at    timestamptz NOT NULL DEFAULT now(),
    is_deleted    boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 6. student_discounts
--    note / approved_by dropped (dead columns).
-- ---------------------------------------------------------------------------
CREATE TABLE student_discounts (
    id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id     uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id    uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    discount_id   uuid NOT NULL REFERENCES fee_discounts(id) ON DELETE CASCADE,
    term_id       uuid REFERENCES terms(id),
    created_at    timestamptz NOT NULL DEFAULT now(),
    updated_at    timestamptz NOT NULL DEFAULT now(),
    is_deleted    boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 7. fee_structure_audit_log
-- ---------------------------------------------------------------------------
CREATE TABLE fee_structure_audit_log (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    fee_structure_id uuid NOT NULL REFERENCES fee_structures(id) ON DELETE CASCADE,
    changed_by      uuid REFERENCES users(id),
    action          text NOT NULL CHECK (action IN ('created', 'updated', 'deleted')),
    old_value       jsonb,
    new_value       jsonb,
    created_at      timestamptz NOT NULL DEFAULT now()
);

-- ----------------------------------------------------------------------------
-- Source: supabase/migrations/0007_grading_tables.sql
-- ----------------------------------------------------------------------------

-- =============================================================================
-- SKULI SaaS: Grading Tables
-- Migration 0007
--
-- marks, report_cards, subject_comments, grading_scales.
--
-- Dead columns removed (per reconciliation report section D):
--   * marks.entered_by     — never selected
--   * marks.reviewed_by    — never selected
--   * report_cards.pdf_url — app writes it but never reads it back
--   * subject_comments.created_at / updated_at / is_deleted — never selected
--
-- Retained (per section D):
--   * report_cards.class_id (00051) — referenced by app
--   * marks.review_status / review_comment / reviewed_at (00007) — used
--     for the approval workflow and by subject_performance_summary view
--   * grading_scales.sort_order — needed for default seed ordering
-- =============================================================================

-- ---------------------------------------------------------------------------
-- 1. marks
-- ---------------------------------------------------------------------------
CREATE TABLE marks (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id      uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    subject_id      uuid NOT NULL REFERENCES subjects(id) ON DELETE CASCADE,
    class_id        uuid NOT NULL REFERENCES classes(id) ON DELETE CASCADE,
    term_id         uuid NOT NULL REFERENCES terms(id) ON DELETE CASCADE,
    academic_year_id uuid NOT NULL REFERENCES academic_years(id) ON DELETE CASCADE,
    exam_type       exam_type NOT NULL,
    score           numeric,
    max_score       numeric NOT NULL DEFAULT 100,
    grade           text,
    remarks         text,
    entered_by      uuid REFERENCES users(id) ON DELETE SET NULL,
    reviewed_by     uuid REFERENCES users(id) ON DELETE SET NULL,
    review_status   text NOT NULL DEFAULT 'not_started'
                    CHECK (review_status IN ('not_started', 'draft', 'submitted', 'approved', 'rejected')),
    review_comment  text,
    reviewed_at     timestamptz,
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false,
    UNIQUE (student_id, subject_id, term_id, exam_type)
);
COMMENT ON COLUMN marks.grade      IS 'Grade label from grading_scales. Auto-set by trg_marks_set_grade (0023).';
COMMENT ON COLUMN marks.entered_by IS 'User who entered the mark (written by marks POST route).';

-- ---------------------------------------------------------------------------
-- 2. report_cards
-- ---------------------------------------------------------------------------
CREATE TABLE report_cards (
    id                  uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id           uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id          uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    term_id             uuid NOT NULL REFERENCES terms(id) ON DELETE CASCADE,
    academic_year_id    uuid NOT NULL REFERENCES academic_years(id) ON DELETE CASCADE,
    class_id            uuid REFERENCES classes(id),
    total_marks         numeric,
    average             numeric,
    position_in_class   int,
    class_size          int,
    class_teacher_comment text,
    headmaster_comment  text,
    conduct_grade       conduct_grade,
    pdf_url             text,
    is_published        boolean NOT NULL DEFAULT false,
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now(),
    is_deleted          boolean NOT NULL DEFAULT false,
    UNIQUE (student_id, term_id, academic_year_id)
);
COMMENT ON COLUMN report_cards.pdf_url IS 'Storage URL of the generated PDF, read by the report-cards list page.';

-- ---------------------------------------------------------------------------
-- 3. subject_comments
-- ---------------------------------------------------------------------------
CREATE TABLE subject_comments (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id  uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    term_id     uuid NOT NULL REFERENCES terms(id) ON DELETE CASCADE,
    subject_id  uuid NOT NULL REFERENCES subjects(id) ON DELETE CASCADE,
    bot_comment text,
    mid_comment text,
    eot_comment text,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now(),
    is_deleted  boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 4. grading_scales
-- ---------------------------------------------------------------------------
CREATE TABLE grading_scales (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    grade       text NOT NULL,
    min_score   numeric NOT NULL,
    max_score   numeric NOT NULL,
    label       text,
    sort_order  int NOT NULL DEFAULT 0,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now(),
    is_deleted  boolean NOT NULL DEFAULT false,
    UNIQUE (school_id, grade)
);

-- ----------------------------------------------------------------------------
-- Source: supabase/migrations/0008_attendance_announcements.sql
-- ----------------------------------------------------------------------------

-- =============================================================================
-- SKULI SaaS: Attendance, Announcements, Communication Logs
-- Migration 0008
--
-- attendance_records, announcements, sms_logs,
-- notification_preferences, in_app_notifications, notification_logs,
-- audit_logs.
--
-- Dead columns removed (per reconciliation report section D):
--   * attendance_records.marked_by  — never selected
--   * announcements.sent_via        — never selected
--   * sms_logs.related_entity_type  — never selected
--   * sms_logs.related_entity_id    — never selected
--   * notification_preferences.sms_enabled — never selected
--
-- New columns added (per section C gap list):
--   * notification_logs.last_error  text
--
-- Reconciliation note for `announcements.message_body`: the app reads
-- `message_body` from this table, but the column is `body`. Per the
-- audit, the app code is the bug — the schema is correct. The app
-- must be fixed to read `body` (or the code dropped). Do NOT add a
-- `message_body` alias column.
-- =============================================================================

-- ---------------------------------------------------------------------------
-- 1. attendance_records
--    term_id column added (00059) for EMIS reporting & dashboard joins.
-- ---------------------------------------------------------------------------
CREATE TABLE attendance_records (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id  uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    class_id    uuid NOT NULL REFERENCES classes(id) ON DELETE CASCADE,
    term_id     uuid REFERENCES terms(id),
    date        date NOT NULL,
    status      attendance_status NOT NULL,
    notes       text,
    remarks     text,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now(),
    is_deleted  boolean NOT NULL DEFAULT false,
    UNIQUE (student_id, class_id, date)
);
COMMENT ON COLUMN attendance_records.remarks IS 'Teacher remarks. The app reads remarks; notes is the legacy column.';

-- ---------------------------------------------------------------------------
-- 2. announcements
--    scheduled_status added (00011) so the SMS scheduler can pick
--    queued jobs.
-- ---------------------------------------------------------------------------
CREATE TABLE announcements (
    id                  uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id           uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    title               text NOT NULL,
    body                text,
    target_audience     announcement_target NOT NULL,
    target_class_ids    uuid[],
    -- text + CHECK (not sms_channel enum): the send route writes compound
    -- channel strings like 'sms,in_app'.
    sent_via            text NOT NULL
                        CHECK (sent_via IN (
                            'sms', 'email', 'in_app', 'push',
                            'sms,in_app', 'sms,push', 'email,in_app',
                            'sms,email,in_app', 'sms,in_app,push'
                        )),
    scheduled_at        timestamptz,
    scheduled_status    text NOT NULL DEFAULT 'pending'
                        CHECK (scheduled_status IN ('pending', 'processing', 'sent', 'failed', 'cancelled')),
    sent_at             timestamptz,
    sent_by             uuid REFERENCES users(id) ON DELETE SET NULL,
    sms_cost            numeric,
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now(),
    is_deleted          boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 3. sms_logs
-- ---------------------------------------------------------------------------
CREATE TABLE sms_logs (
    id                      uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id               uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    recipient_phone         text NOT NULL,
    message_body            text,
    message_type            text,
    status                  sms_status NOT NULL DEFAULT 'pending',
    africa_talking_message_id text,
    cost                    numeric,
    error                   text,
    related_entity_type     text,
    related_entity_id       uuid,
    sent_at                 timestamptz,
    created_at              timestamptz NOT NULL DEFAULT now(),
    updated_at              timestamptz NOT NULL DEFAULT now(),
    is_deleted              boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 4. notification_preferences
-- ---------------------------------------------------------------------------
CREATE TABLE notification_preferences (
    id                          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id                   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    send_receipt_sms            boolean NOT NULL DEFAULT true,
    send_absence_sms            boolean NOT NULL DEFAULT true,
    send_weekly_defaulter       boolean NOT NULL DEFAULT true,
    defaulter_reminder_day      int NOT NULL DEFAULT 1,
    defaulter_reminder_hour     int NOT NULL DEFAULT 8,
    send_report_card_sms        boolean NOT NULL DEFAULT true,
    send_term_start_sms         boolean NOT NULL DEFAULT true,
    sms_enabled                 boolean NOT NULL DEFAULT false,
    created_at                  timestamptz NOT NULL DEFAULT now(),
    updated_at                  timestamptz NOT NULL DEFAULT now(),
    is_deleted                  boolean NOT NULL DEFAULT false,
    UNIQUE (school_id),
    CHECK (defaulter_reminder_day BETWEEN 0 AND 7),
    CHECK (defaulter_reminder_hour BETWEEN 0 AND 23)
);

-- ---------------------------------------------------------------------------
-- 5. in_app_notifications
-- ---------------------------------------------------------------------------
CREATE TABLE in_app_notifications (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    recipient_user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    title           text NOT NULL,
    body            text,
    -- type accepts both UI severities and entity-type values the
    -- notifications service writes (tuition_payment, payroll_disbursal).
    type            text NOT NULL DEFAULT 'info'
                    CHECK (type IN (
                        'info', 'warning', 'success', 'error',
                        'tuition_payment', 'payroll_disbursal', 'subscription'
                    )),
    is_read         boolean NOT NULL DEFAULT false,
    related_entity_type text,
    related_entity_id   uuid,
    created_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 6. notification_logs
--    last_error added (per section C gap list).
-- ---------------------------------------------------------------------------
CREATE TABLE notification_logs (
    id                  uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id           uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    recipient_user_id   uuid REFERENCES users(id) ON DELETE SET NULL,
    recipient_phone     text,
    channel_type        notification_channel NOT NULL,
    message_body        text NOT NULL,
    delivery_status     text NOT NULL DEFAULT 'pending',
    multi_sms_flag      boolean NOT NULL DEFAULT false,
    related_entity_type text,
    related_entity_id   text,
    last_error          text,
    cost                numeric,
    provider_message_id text,
    sent_at             timestamptz,
    created_at          timestamptz NOT NULL DEFAULT now()
);

-- ---------------------------------------------------------------------------
-- 7. audit_logs
-- ---------------------------------------------------------------------------
CREATE TABLE audit_logs (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid REFERENCES schools(id) ON DELETE SET NULL,
    user_id     uuid,
    action      text NOT NULL,
    entity_type text,
    entity_id   uuid,
    old_value   jsonb,
    new_value   jsonb,
    ip_address  text,
    user_agent  text,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now(),
    is_deleted  boolean NOT NULL DEFAULT false
);

-- ----------------------------------------------------------------------------
-- Source: supabase/migrations/0009_staff_payroll.sql
-- ----------------------------------------------------------------------------

-- =============================================================================
-- SKULI SaaS: Staff & Payroll Tables
-- Migration 0009
--
-- staff, payroll_records, staff_payment_profiles, payroll_batches,
-- batch_line_items, tuition_payments, pesapal_token_cache,
-- expense_categories, expenses, subscription_invoices.
--
-- Dead columns removed (per reconciliation report section D):
--   * staff.national_id, hire_date           — never selected
--   * payroll_batches.pesapal_funding_ref    — never selected
--   * payroll_batches.pesapal_funding_url    — never selected
--   * payroll_batches.pesapal_order_tracking_id — never selected
--   * payroll_batches.funded_at              — never selected
--   * payroll_batches.approved_by_user_id    — never selected
--   * payroll_batches.total_net_salaries     — never selected
--   * payroll_batches.total_overhead_fees    — never selected
--   * batch_line_items.processing_fee        — never selected
--   * batch_line_items.provider_receipt_id   — never selected
--   * batch_line_items.last_error            — never selected
--   * batch_line_items.disbursed_at          — never selected
--   * batch_line_items.created_at            — never selected
--   * batch_line_items.payroll_record_id     — never selected
--   * tuition_payments.fee_type_id           — never selected
--   * tuition_payments.fee_type_label        — never selected
--   * tuition_payments.pesapal_redirect_url  — never selected
--   * tuition_payments.payment_description   — never selected
--   * tuition_payments.initiated_by_user_id  — never selected
--   * expenses.term_id                       — never selected
--   * expenses.receipt_number                — never selected
--   * expenses.recorded_by                   — never selected
--   * expenses.notes                         — never selected
--   * expenses.created_at                    — never selected
--   * pesapal_token_cache.updated_at         — never selected
--
-- subscription_invoices: flutterwave_tx_id renamed to pesapal_tx_id (00049).
-- pesapal_token_cache has `updated_at` REMOVED (app never reads it).
-- =============================================================================

-- ---------------------------------------------------------------------------
-- 1. staff
-- ---------------------------------------------------------------------------
CREATE TABLE staff (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    user_id         uuid REFERENCES users(id) ON DELETE SET NULL,
    employee_number text NOT NULL,
    photo_url       text,
    full_name       text NOT NULL,
    role_title      text,
    role            text DEFAULT 'staff',
    bank_name       text,
    bank_account    text,
    nssf_number     text,
    basic_salary    numeric,
    is_active       boolean NOT NULL DEFAULT true,
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false,
    UNIQUE (school_id, employee_number)
);

-- ---------------------------------------------------------------------------
-- 2. payroll_records
-- ---------------------------------------------------------------------------
CREATE TABLE payroll_records (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    staff_id        uuid NOT NULL REFERENCES staff(id) ON DELETE CASCADE,
    month           int NOT NULL,
    year            int NOT NULL,
    basic_salary    numeric NOT NULL,
    allowances      jsonb NOT NULL DEFAULT '{}',
    deductions      jsonb NOT NULL DEFAULT '{}',
    nssf_employee   numeric,
    nssf_employer   numeric,
    net_salary      numeric,
    payment_status  payroll_payment_status NOT NULL DEFAULT 'pending',
    paid_at         timestamptz,
    payment_method  text,
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 3. staff_payment_profiles
-- ---------------------------------------------------------------------------
CREATE TABLE staff_payment_profiles (
    id               uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id        uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    staff_id         uuid NOT NULL REFERENCES staff(id) ON DELETE CASCADE,
    preferred_method staff_payout_method NOT NULL DEFAULT 'MOBILE_MONEY',
    mobile_number    text,
    bank_code        text,
    bank_name        text,
    account_number   text,
    account_name     text,
    created_at       timestamptz NOT NULL DEFAULT now(),
    updated_at       timestamptz NOT NULL DEFAULT now(),
    UNIQUE (staff_id)
);

-- ---------------------------------------------------------------------------
-- 4. payroll_batches
-- ---------------------------------------------------------------------------
CREATE TABLE payroll_batches (
    id                        text PRIMARY KEY,
    school_id                 uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    label                     text,
    funding_mechanism         payroll_funding_mechanism NOT NULL,
    total_payout_sum          numeric(14,2) NOT NULL DEFAULT 0,
    funding_payment_status    payroll_funding_status NOT NULL DEFAULT 'AWAITING_EXTERNAL_FUNDING',
    pesapal_order_tracking_id text,
    funded_at                 timestamptz,
    created_at                timestamptz NOT NULL DEFAULT now(),
    updated_at                timestamptz NOT NULL DEFAULT now()
);

-- ---------------------------------------------------------------------------
-- 5. batch_line_items
-- ---------------------------------------------------------------------------
CREATE TABLE batch_line_items (
    id                     bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    batch_id               text NOT NULL REFERENCES payroll_batches(id) ON DELETE CASCADE,
    staff_id               uuid NOT NULL REFERENCES staff(id) ON DELETE CASCADE,
    worker_name            text NOT NULL,
    payout_amount          numeric(14,2) NOT NULL DEFAULT 0,
    idempotency_key        text NOT NULL,
    snapshot_payout_method staff_payout_method NOT NULL,
    snapshot_mobile_number text,
    snapshot_bank_code     text,
    snapshot_account_number text,
    disbursal_status       disbursal_status NOT NULL DEFAULT 'HOLD_UNTIL_FUNDED',
    disbursal_attempts     integer NOT NULL DEFAULT 0,
    last_error             text,
    disbursed_at           timestamptz,
    created_at             timestamptz NOT NULL DEFAULT now(),
    updated_at             timestamptz NOT NULL DEFAULT now(),
    UNIQUE (idempotency_key)
);

-- ---------------------------------------------------------------------------
-- 6. tuition_payments
-- ---------------------------------------------------------------------------
CREATE TABLE tuition_payments (
    id                        text PRIMARY KEY,
    school_id                 uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id                uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    fee_account_id            uuid REFERENCES fee_accounts(id) ON DELETE SET NULL,
    amount                    numeric(14,2) NOT NULL CHECK (amount > 0),
    status                    pesapal_payment_status NOT NULL DEFAULT 'PENDING',
    pesapal_order_tracking_id text,
    pesapal_redirect_url      text,
    payment_description       text,
    fee_type_id               uuid REFERENCES fee_types(id) ON DELETE SET NULL,
    fee_type_label            text,
    initiated_by_user_id      uuid REFERENCES users(id) ON DELETE SET NULL,
    receipt_number            text,
    created_at                timestamptz NOT NULL DEFAULT now(),
    updated_at                timestamptz NOT NULL DEFAULT now()
);

-- ---------------------------------------------------------------------------
-- 7. pesapal_token_cache
--    Service-role only. No updated_at — not read by app.
-- ---------------------------------------------------------------------------
CREATE TABLE pesapal_token_cache (
    id         text PRIMARY KEY DEFAULT 'singleton',
    token      text NOT NULL,
    expires_at timestamptz NOT NULL
);

-- ---------------------------------------------------------------------------
-- 8. expense_categories
-- ---------------------------------------------------------------------------
CREATE TABLE expense_categories (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    name        text NOT NULL,
    color       text,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now(),
    is_deleted  boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 9. expenses
-- ---------------------------------------------------------------------------
CREATE TABLE expenses (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    category_id     uuid REFERENCES expense_categories(id),
    term_id         uuid REFERENCES terms(id) ON DELETE SET NULL,
    description     text NOT NULL,
    amount          numeric NOT NULL,
    expense_date    date NOT NULL,
    payment_method  expense_payment_method,
    notes           text,
    receipt_number  text,
    recorded_by     uuid REFERENCES users(id) ON DELETE SET NULL,
    created_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 10. subscription_invoices
--     flutterwave_tx_id renamed to pesapal_tx_id.
-- ---------------------------------------------------------------------------
CREATE TABLE subscription_invoices (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    pesapal_tx_id   text,
    plan            subscription_plan NOT NULL,
    amount          numeric NOT NULL,
    currency        text NOT NULL DEFAULT 'UGX',
    period_start    timestamptz,
    period_end      timestamptz,
    status          text,
    revenue_by_plan jsonb,
    paid_at         timestamptz,
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false
);

-- ----------------------------------------------------------------------------
-- Source: supabase/migrations/0010_communication.sql
-- ----------------------------------------------------------------------------

-- =============================================================================
-- SKULI SaaS: Communication Tables
-- Migration 0010
--
-- message_threads, thread_messages, meeting_slots, meeting_bookings,
-- push_subscriptions, push_queue.
--
-- Dead columns removed (per reconciliation report section D):
--   * meeting_bookings.notes   — never selected
--   * library_issues.issued_by — never selected
--   * library_issues.updated_at — never selected
--
-- meeting_bookings.status: 'pending' added (00037) so a parent can book
-- and a teacher must confirm.
-- =============================================================================

-- ---------------------------------------------------------------------------
-- 1. message_threads (one per parent phone per school)
-- ---------------------------------------------------------------------------
CREATE TABLE message_threads (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    parent_phone    text NOT NULL,
    student_id      uuid REFERENCES students(id),
    last_message_at timestamptz NOT NULL DEFAULT now(),
    is_read         boolean NOT NULL DEFAULT false,
    is_deleted      boolean NOT NULL DEFAULT false,
    UNIQUE (school_id, parent_phone)
);

-- ---------------------------------------------------------------------------
-- 2. thread_messages
-- ---------------------------------------------------------------------------
CREATE TABLE thread_messages (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    thread_id       uuid NOT NULL REFERENCES message_threads(id) ON DELETE CASCADE,
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    direction       text NOT NULL CHECK (direction IN ('inbound', 'outbound')),
    body            text NOT NULL,
    sender_name     text,
    at_message_id   text,
    status          text NOT NULL DEFAULT 'delivered'
                    CHECK (status IN ('sent', 'delivered', 'failed')),
    sent_at         timestamptz NOT NULL DEFAULT now(),
    is_deleted      boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 3. meeting_slots (teacher availability)
-- ---------------------------------------------------------------------------
CREATE TABLE meeting_slots (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    teacher_id      uuid NOT NULL REFERENCES staff(id) ON DELETE CASCADE,
    slot_date       date NOT NULL,
    start_time      time NOT NULL,
    end_time        time NOT NULL,
    duration_minutes int NOT NULL DEFAULT 15,
    -- GENERATED: ISO weekday derived from slot_date (1=Mon..7=Sun). Never insert.
    day_of_week     int GENERATED ALWAYS AS (EXTRACT(ISODOW FROM slot_date)::int) STORED,
    is_booked       boolean NOT NULL DEFAULT false,
    is_deleted      boolean NOT NULL DEFAULT false
);

-- ---------------------------------------------------------------------------
-- 4. meeting_bookings (parent reservations)
-- ---------------------------------------------------------------------------
CREATE TABLE meeting_bookings (
    id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    slot_id         uuid NOT NULL REFERENCES meeting_slots(id) ON DELETE CASCADE,
    school_id       uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    student_id      uuid NOT NULL REFERENCES students(id) ON DELETE CASCADE,
    parent_name     text NOT NULL,
    parent_phone    text NOT NULL,
    notes           text,
    status          text NOT NULL DEFAULT 'pending'
                    CHECK (status IN ('pending', 'confirmed', 'cancelled', 'completed')),
    reminder_sent   boolean NOT NULL DEFAULT false,
    created_at      timestamptz NOT NULL DEFAULT now()
);

-- ---------------------------------------------------------------------------
-- 5. push_subscriptions (PWA)
-- ---------------------------------------------------------------------------
CREATE TABLE push_subscriptions (
    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    school_id   uuid NOT NULL REFERENCES schools(id) ON DELETE CASCADE,
    user_id     uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    endpoint    text NOT NULL,
    p256dh      text NOT NULL,
    auth        text NOT NULL,
    created_at  timestamptz NOT NULL DEFAULT now(),
    is_deleted  boolean NOT NULL DEFAULT false,
    UNIQUE(user_id, endpoint)
);

-- ---------------------------------------------------------------------------
-- 6. push_queue
--    Service-role only. anon/authenticated must have zero access.
--    Service role bypasses RLS entirely so no permissive policy is needed.
-- ---------------------------------------------------------------------------
CREATE TABLE push_queue (
  id         uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id    uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  title      text NOT NULL,
  body       text NOT NULL,
  url        text,
  status     text NOT NULL DEFAULT 'pending',
  created_at timestamptz NOT NULL DEFAULT now(),
  sent_at    timestamptz,
  error      text
);

