INSERT INTO school_groups (id, name, code, created_at, is_deleted) VALUES
    ('00000000-0000-0000-0000-000000000001'::uuid,
     'SKULI Demo Chain', 'DEMO', now(), false)
ON CONFLICT (code) DO NOTHING;

